    /// Fetch an object from GCS
    ///
    /// # Arguments
    /// * `path` - Relative path within the bucket (e.g., "content/abc123/playlist.m3u8")
    ///
    /// # Returns
    /// Tuple of (data, content_type)
    pub async fn get_object(&self, path: &str) -> Result<(Bytes, String)> {
